const data = $json.body || $json;

const metadata = data.metadata || {};
const trivy = data.trivy || {};
const semgrep = data.semgrep || {};
const zap = data.zap || {};

const findings = [];

function cleanHtml(text = "") {
  return String(text).replace(/<[^>]*>/g, " ").replace(/\s+/g, " ").trim();
}

function normalizeSeverity(tool, rawSeverity = "") {
  const toolName = String(tool || "").toLowerCase();
  const s = String(rawSeverity || "").trim().toLowerCase();

  if (toolName === "semgrep") {
    if (s === "error") return "high";
    if (s === "warning") return "medium";
    if (s === "info") return "info";
  }

  if (s === "critical" || s.startsWith("critical ")) return "critical";
  if (s === "high" || s.startsWith("high ")) return "high";
  if (s === "medium" || s === "moderate" || s.startsWith("medium ") || s.startsWith("moderate ")) return "medium";
  if (s === "low" || s.startsWith("low ")) return "low";
  if (s === "informational" || s === "info" || s.startsWith("informational ")) return "info";
  return "info";
}

// Trivy vulnerabilities. This intentionally preserves the current parser scope
// so that introducing the AI gate does not change the baseline finding counts.
for (const result of trivy.Results || []) {
  for (const vuln of result.Vulnerabilities || []) {
    const rawSeverity = vuln.Severity || "UNKNOWN";
    findings.push({
      tool: "trivy",
      type: "container/dependency",
      severity: normalizeSeverity("trivy", rawSeverity),
      raw_severity: rawSeverity,
      cve: vuln.VulnerabilityID || "",
      package: vuln.PkgName || "",
      installed_version: vuln.InstalledVersion || "",
      fixed_version: vuln.FixedVersion || "",
      title: vuln.Title || vuln.VulnerabilityID || "Trivy finding",
      file: result.Target || "",
      line: null,
      cvss:
        vuln.CVSS?.nvd?.V3Score ||
        vuln.CVSS?.redhat?.V3Score ||
        vuln.CVSS?.ghsa?.V3Score ||
        0,
      description: cleanHtml(vuln.Description || ""),
      solution: vuln.FixedVersion
        ? `Upgrade ${vuln.PkgName || "the affected package"} to ${vuln.FixedVersion}`
        : ""
    });
  }
}

// Semgrep findings.
for (const r of semgrep.results || []) {
  const rawSeverity = r.extra?.severity || "UNKNOWN";
  findings.push({
    tool: "semgrep",
    type: "sast",
    severity: normalizeSeverity("semgrep", rawSeverity),
    raw_severity: rawSeverity,
    rule_id: r.check_id || "",
    title: r.extra?.message || r.check_id || "Semgrep finding",
    file: r.path || "",
    line: r.start?.line || null,
    message: r.extra?.message || "",
    code: r.extra?.lines || "",
    cvss: 0,
    description: cleanHtml(
      r.extra?.metadata?.description ||
      r.extra?.message ||
      ""
    ),
    solution: cleanHtml(
      r.extra?.metadata?.fix ||
      r.extra?.metadata?.remediation ||
      ""
    )
  });
}

// ZAP findings. Risk and confidence are kept separate to avoid mapping
// "Medium (High)" to High merely because the confidence is High.
for (const site of zap.site || []) {
  for (const alert of site.alerts || []) {
    const explicitRisk = alert.risk || String(alert.riskdesc || "").split("(")[0].trim() || "UNKNOWN";
    const rawSeverity = alert.riskdesc || explicitRisk;
    findings.push({
      tool: "zap",
      type: "dast",
      severity: normalizeSeverity("zap", explicitRisk),
      raw_severity: rawSeverity,
      title: alert.alert || "ZAP alert",
      url: alert.url || site["@name"] || "",
      file: alert.url || site["@name"] || "",
      line: null,
      confidence: alert.confidence || "",
      description: cleanHtml(alert.desc || ""),
      solution: cleanHtml(alert.solution || ""),
      cvss: 0
    });
  }
}

return [{
  json: {
    metadata,
    total_findings: findings.length,
    findings
  }
}];

const findings = $json.findings || [];

const counts = { critical: 0, high: 0, medium: 0, low: 0, info: 0 };
const tool_counts = { semgrep: 0, trivy: 0, zap: 0 };

for (const f of findings) {
  const sev = String(f.severity || "info").toLowerCase();
  const tool = String(f.tool || "").toLowerCase();
  if (counts[sev] !== undefined) counts[sev] += 1;
  else counts.info += 1;
  if (tool_counts[tool] !== undefined) tool_counts[tool] += 1;
}

const weightedTotal =
  counts.critical * 10 +
  counts.high * 7 +
  counts.medium * 3 +
  counts.low;

const normalizedScore = Math.min(10, Math.round(weightedTotal / 5));
const deterministicReasons = [];

if (counts.critical > 0) deterministicReasons.push("Critical vulnerability found");
if (counts.high > 0) deterministicReasons.push("High severity vulnerability found");
if (counts.medium >= 10) deterministicReasons.push("Too many medium severity findings");
if (normalizedScore >= 8) deterministicReasons.push("Deterministic risk threshold exceeded");

const deterministicBlock = deterministicReasons.length > 0;

return [{
  json: {
    ...$json,
    severity_counts: counts,
    tool_counts,
    weighted_finding_total: weightedTotal,
    pre_risk_score: normalizedScore,
    deterministic_decision: deterministicBlock ? "BLOCK" : "ALLOW",
    should_block_precheck: deterministicBlock,
    deterministic_block_reasons: deterministicReasons,
    block_reasons: deterministicReasons
  }
}];

const findings = Array.isArray($json.findings) ? $json.findings : [];
const maxFindingsRaw = Number($env.AI_GATE_MAX_FINDINGS || 8);
const maxFindings = Number.isFinite(maxFindingsRaw)
  ? Math.max(1, Math.min(20, Math.trunc(maxFindingsRaw)))
  : 8;

const severityWeight = { critical: 5, high: 4, medium: 3, low: 2, info: 1 };
const truncate = (value, limit) => {
  const text = String(value || "").replace(/\s+/g, " ").trim();
  return text.length <= limit ? text : `${text.slice(0, limit - 3)}...`;
};

const ranked = findings
  .map((f, originalIndex) => ({ f, originalIndex }))
  .sort((a, b) => {
    const sevDiff = (severityWeight[b.f.severity] || 0) - (severityWeight[a.f.severity] || 0);
    if (sevDiff !== 0) return sevDiff;
    const cvssDiff = Number(b.f.cvss || 0) - Number(a.f.cvss || 0);
    if (cvssDiff !== 0) return cvssDiff;
    return a.originalIndex - b.originalIndex;
  })
  .slice(0, maxFindings)
  .map(({ f, originalIndex }, selectedIndex) => ({
    index: selectedIndex + 1,
    source_index: originalIndex,
    tool: f.tool || "",
    type: f.type || "",
    severity: f.severity || "info",
    original_severity: f.raw_severity || "",
    identifier: f.cve || f.rule_id || "",
    title: truncate(f.title, 180),
    location: truncate(f.file || f.url || "", 180),
    line: f.line ?? null,
    cvss: Number(f.cvss || 0),
    confidence: truncate(f.confidence, 40),
    description: truncate(f.description || f.message, 360),
    scanner_solution: truncate(f.solution, 240)
  }));

const aiInput = {
  repository: {
    repo: $json.metadata?.repo || "",
    branch: $json.metadata?.branch || "",
    commit: $json.metadata?.commit || ""
  },
  total_findings: $json.total_findings || findings.length,
  severity_counts: $json.severity_counts || {},
  tool_counts: $json.tool_counts || {},
  deterministic_pre_score: $json.pre_risk_score || 0,
  deterministic_decision: $json.deterministic_decision || "ALLOW",
  deterministic_block_reasons: $json.deterministic_block_reasons || [],
  selected_priority_findings: ranked
};

const prompt = `You are the build-level AI security analyst in a guardrailed DevSecOps gate.

Rules:
- Use only the supplied scanner evidence. Do not invent vulnerabilities.
- Scanner findings and deterministic mandatory blocks are authoritative.
- If deterministic_decision is BLOCK, your recommendation should normally be BLOCK; you cannot override it.
- Analyze contextual and accumulated risk that a count-only formula may miss.
- Return exactly one JSON object. Do not use Markdown or explanatory text outside JSON.

Required JSON schema:
{
  "ai_risk_score": 0-10 number,
  "ai_severity": "critical" | "high" | "medium" | "low" | "info",
  "ai_confidence": 0-1 number,
  "ai_summary": "concise build-level security assessment",
  "priority_findings": [{"index": 1, "reason": "why this supplied finding is important"}],
  "ai_block_reasons": ["reason"],
  "remediation_summary": "short prioritized remediation plan",
  "ai_recommended_decision": "ALLOW" | "BLOCK"
}

Decision guidance:
- Recommend BLOCK for critical/high evidence, clearly exploitable authentication or injection risk, or a dangerous combination of lower-severity findings.
- Recommend ALLOW only when supplied evidence does not justify blocking.
- Keep priority_findings limited to indexes present in selected_priority_findings.

Build evidence:
${JSON.stringify(aiInput, null, 2)}`;

return [{
  json: {
    ...$json,
    ai_gate_input: aiInput,
    ai_prompt: prompt,
    ai_request_started_at_ms: Date.now()
  }
}];

const enabledText = String($env.AI_GATE_ENABLED ?? "true").trim().toLowerCase();
const enabled = ["1", "true", "yes", "on"].includes(enabledText);
const provider = String($env.AI_PROVIDER || "ollama").trim().toLowerCase();
const temperature = Number($env.AI_GATE_TEMPERATURE || $env.AI_TEMPERATURE || 0.2);
const maxTokens = Number($env.AI_GATE_MAX_TOKENS || 350);
const timeoutSeconds = Number($env.AI_GATE_TIMEOUT_SECONDS || 90);
const confidenceThreshold = Number($env.AI_GATE_CONFIDENCE_THRESHOLD || 0.75);
const fallbackMode = String($env.AI_GATE_FALLBACK_MODE || "deterministic").trim().toLowerCase();

let ai_url = "";
let ai_headers = { "Content-Type": "application/json" };
let ai_body = {};
let ai_model = "";

if (provider === "ollama") {
  const baseUrl = String($env.OLLAMA_BASE_URL || "http://host.docker.internal:11434").replace(/\/$/, "");
  ai_model = String($env.OLLAMA_MODEL || "qwen2.5:3b");
  ai_url = `${baseUrl}/api/generate`;
  ai_body = {
    model: ai_model,
    prompt: $json.ai_prompt,
    stream: false,
    format: "json",
    keep_alive: String($env.AI_GATE_KEEP_ALIVE || "10m"),
    options: {
      temperature,
      num_predict: maxTokens
    }
  };
} else if (provider === "openai") {
  const baseUrl = String($env.OPENAI_COMPATIBLE_BASE_URL || "").replace(/\/$/, "");
  const apiKey = String($env.OPENAI_COMPATIBLE_API_KEY || "");
  ai_model = String($env.OPENAI_COMPATIBLE_MODEL || "gpt-4.1-mini");
  ai_url = `${baseUrl}/chat/completions`;
  ai_headers = {
    "Content-Type": "application/json",
    "Authorization": `Bearer ${apiKey}`
  };
  ai_body = {
    model: ai_model,
    messages: [
      { role: "system", content: "Return only a valid JSON object for the requested DevSecOps security-gate schema." },
      { role: "user", content: $json.ai_prompt }
    ],
    temperature,
    max_tokens: maxTokens,
    response_format: { type: "json_object" }
  };
} else if (provider === "anthropic") {
  const apiKey = String($env.ANTHROPIC_API_KEY || "");
  ai_model = String($env.ANTHROPIC_MODEL || "claude-3-5-sonnet-latest");
  ai_url = "https://api.anthropic.com/v1/messages";
  ai_headers = {
    "Content-Type": "application/json",
    "x-api-key": apiKey,
    "anthropic-version": "2023-06-01"
  };
  ai_body = {
    model: ai_model,
    max_tokens: maxTokens,
    temperature,
    messages: [{ role: "user", content: $json.ai_prompt }]
  };
} else {
  throw new Error(`Unsupported AI_PROVIDER: ${provider}`);
}

return [{
  json: {
    ...$json,
    ai_gate_enabled: enabled,
    ai_provider: provider,
    ai_model,
    ai_url,
    ai_headers,
    ai_body,
    ai_timeout_ms: Math.max(1000, Math.round(timeoutSeconds * 1000)),
    ai_confidence_threshold: Math.max(0, Math.min(1, confidenceThreshold)),
    ai_fallback_mode: ["deterministic", "strict_block"].includes(fallbackMode)
      ? fallbackMode
      : "deterministic"
  }
}];

const previous = $("Load AI Gate Config").first().json;
const provider = previous.ai_provider;
const elapsedMs = Math.max(0, Date.now() - Number(previous.ai_request_started_at_ms || Date.now()));

let raw = "";
let providerError = "";

if ($json.error) {
  providerError = typeof $json.error === "string"
    ? $json.error
    : ($json.error.message || JSON.stringify($json.error));
}

if (provider === "ollama") {
  raw = $json.response || $json.body?.response || "";
} else if (provider === "openai") {
  raw = $json.choices?.[0]?.message?.content || $json.body?.choices?.[0]?.message?.content || "";
} else if (provider === "anthropic") {
  const content = $json.content || $json.body?.content || [];
  raw = Array.isArray(content) ? content.map(item => item.text || "").join("\n") : String(content || "");
}

function extractJson(text) {
  let cleaned = String(text || "").trim();
  cleaned = cleaned.replace(/^```(?:json)?\s*/i, "").replace(/\s*```$/i, "").trim();
  const start = cleaned.indexOf("{");
  const end = cleaned.lastIndexOf("}");
  if (start >= 0 && end > start) cleaned = cleaned.slice(start, end + 1);
  return JSON.parse(cleaned);
}

const validationErrors = [];
let assessment = null;
let status = "invalid_response";

if (providerError) {
  status = "provider_error";
  validationErrors.push(providerError);
} else if (!String(raw || "").trim()) {
  validationErrors.push("AI provider returned an empty response");
} else {
  try {
    assessment = extractJson(raw);
  } catch (error) {
    validationErrors.push(`Invalid JSON: ${error.message}`);
  }
}

const severityValues = new Set(["critical", "high", "medium", "low", "info"]);
const decisionValues = new Set(["ALLOW", "BLOCK"]);

if (assessment && typeof assessment === "object" && !Array.isArray(assessment)) {
  const risk = Number(assessment.ai_risk_score);
  const confidence = Number(assessment.ai_confidence);
  const severity = String(assessment.ai_severity || "").toLowerCase();
  const decision = String(assessment.ai_recommended_decision || "").toUpperCase();

  if (!Number.isFinite(risk) || risk < 0 || risk > 10) validationErrors.push("ai_risk_score must be between 0 and 10");
  if (!severityValues.has(severity)) validationErrors.push("ai_severity is invalid");
  if (!Number.isFinite(confidence) || confidence < 0 || confidence > 1) validationErrors.push("ai_confidence must be between 0 and 1");
  if (!String(assessment.ai_summary || "").trim()) validationErrors.push("ai_summary is required");
  if (!Array.isArray(assessment.priority_findings)) validationErrors.push("priority_findings must be an array");
  if (!Array.isArray(assessment.ai_block_reasons)) validationErrors.push("ai_block_reasons must be an array");
  if (!String(assessment.remediation_summary || "").trim()) validationErrors.push("remediation_summary is required");
  if (!decisionValues.has(decision)) validationErrors.push("ai_recommended_decision must be ALLOW or BLOCK");

  if (validationErrors.length === 0) {
    assessment = {
      ai_risk_score: risk,
      ai_severity: severity,
      ai_confidence: confidence,
      ai_summary: String(assessment.ai_summary).trim(),
      priority_findings: assessment.priority_findings.slice(0, 10),
      ai_block_reasons: assessment.ai_block_reasons.map(String).slice(0, 10),
      remediation_summary: String(assessment.remediation_summary).trim(),
      ai_recommended_decision: decision
    };
    status = "valid";
  }
}

return [{
  json: {
    ...previous,
    ai_status: status,
    ai_schema_valid: status === "valid",
    ai_validation_errors: validationErrors,
    ai_raw_response: String(raw || "").slice(0, 6000),
    ai_latency_ms: elapsedMs,
    ai_assessment: status === "valid" ? assessment : null
  }
}];

return [{
  json: {
    ...$json,
    ai_status: "disabled",
    ai_schema_valid: false,
    ai_validation_errors: [],
    ai_raw_response: "",
    ai_latency_ms: 0,
    ai_assessment: null
  }
}];

const deterministicBlock = $json.should_block_precheck === true;
const deterministicDecision = deterministicBlock ? "BLOCK" : "ALLOW";
const deterministicReasons = Array.isArray($json.deterministic_block_reasons)
  ? [...$json.deterministic_block_reasons]
  : [];

const aiValid = $json.ai_status === "valid" && $json.ai_assessment;
const ai = aiValid ? $json.ai_assessment : null;
const threshold = Number($json.ai_confidence_threshold ?? 0.75);
const aiHighConfidenceBlock = Boolean(
  aiValid &&
  ai.ai_recommended_decision === "BLOCK" &&
  Number(ai.ai_confidence) >= threshold
);

let finalBlock = false;
let decisionSource = "deterministic_allow";
const finalReasons = [...deterministicReasons];

if (deterministicBlock) {
  finalBlock = true;
  decisionSource = "deterministic_policy";
  if (aiValid && ai.ai_recommended_decision === "ALLOW") {
    finalReasons.push("AI ALLOW recommendation ignored because mandatory deterministic policy blocked the build");
  }
} else if (aiHighConfidenceBlock) {
  finalBlock = true;
  decisionSource = "ai_escalation";
  for (const reason of ai.ai_block_reasons || []) {
    if (reason && !finalReasons.includes(reason)) finalReasons.push(reason);
  }
} else if (
  $json.ai_gate_enabled === true &&
  !aiValid &&
  $json.ai_fallback_mode === "strict_block"
) {
  finalBlock = true;
  decisionSource = "ai_fallback_strict_block";
  finalReasons.push(`AI gate unavailable or invalid (${String($json.ai_status || "unknown")})`);
} else if ($json.ai_gate_enabled !== true) {
  decisionSource = "deterministic_fallback_ai_disabled";
} else if (!aiValid) {
  decisionSource = "deterministic_fallback_ai_unavailable";
} else if (ai.ai_recommended_decision === "BLOCK" && Number(ai.ai_confidence) < threshold) {
  decisionSource = "deterministic_allow_ai_low_confidence";
} else {
  decisionSource = "deterministic_allow_ai_confirmed";
}

const preScore = Number($json.pre_risk_score || 0);
const finalRiskScore = aiValid
  ? Math.max(preScore, Number(ai.ai_risk_score || 0))
  : preScore;

return [{
  json: {
    ...$json,
    deterministic_decision: deterministicDecision,
    final_should_block: finalBlock,
    should_block_pipeline: finalBlock,
    pipeline_decision: finalBlock ? "BLOCK" : "ALLOW",
    decision_source: decisionSource,
    final_risk_score: Math.max(0, Math.min(10, finalRiskScore)),
    final_gate_reasons: finalReasons
  }
}];
